def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 8):
            weight = (8 - j) / 28
            partial_ratio = ratio ** j
            score += weight * partial_ratio
        if capacity < item * 1.2:
            score *= 1.5
            for k in range(1, 4):
                score += (ratio ** k) / (k + 1)
        elif capacity < item * 2:
            for m in range(3, 6):
                score *= (1 + 0.05 * m)
        else:
            if capacity > item * 4:
                score *= 0.7
            elif capacity > item * 3:
                score *= 0.85
            else:
                for n in range(1, 3):
                    score -= 0.02 * n
        if score < 0:
            score = 0
        priorities[i] = score
    return priorities
